{
  "questions": [
    {
      "q": "The K in KNN stands for what?",
      "options": [
        "Kernel",
        "Neighbors",
        "Classes",
        "Distance"
      ],
      "answer": "Neighbors"
    },
    {
      "q": "How does the value of k affect the performance of a KNN classifier?",
      "options": [
        "Increasing k reduces overfitting but increases bias",
        "Decreasing k reduces variance but increases bias",
        "There is no relationship between k and bias/variance tradeoff",
        "k only affects computation time, not model performance"
      ],
      "answer": "Increasing k reduces overfitting but increases bias"
    },
    {
      "q": "KNN is classified as a:",
      "options": [
        "Supervised learning algorithm",
        "Unsupervised learning algorithm",
        "Semi-supervised learning algorithm",
        "Reinforcement learning algorithm"
      ],
      "answer": "Supervised learning algorithm"
    },
    {
      "q": "What is the main disadvantage of using KNN for large datasets?",
      "options": [
        "High computational cost",
        "Poor generalization to unseen data",
        "Difficulty in choosing the optimal value of k",
        "Prone to overfitting"
      ],
      "answer": "High computational cost"
    }
  ]
}
